+// ---------------------------------------------------------------------------
+// User message (AI Elements Message)
+// ---------------------------------------------------------------------------
+
+function UserMessageView({ message }: { message: UserMessage }) {
+  const text =
+    typeof message.content === "string"
+      ? message.content
+      : message.content
+          .filter((c): c is TextContent => c.type === "text")
+          .map((c) => c.text)
+          .join("\n");
